import{_ as s,o as t,c as o,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Securite","description":"","frontmatter":{},"headers":[],"relativePath":"fr/account/security.md","filePath":"fr/account/security.md"}'),a={name:"fr/account/security.md"};function n(r,e,l,u,c,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="securite" tabindex="-1">Securite <a class="header-anchor" href="#securite" aria-label="Permalink to &quot;Securite&quot;">​</a></h1><p>Protegez votre compte avec une authentification forte et surveillez les acces.</p><h2 id="mot-de-passe" tabindex="-1">Mot de passe <a class="header-anchor" href="#mot-de-passe" aria-label="Permalink to &quot;Mot de passe&quot;">​</a></h2><p>Utilisez un mot de passe fort et unique pour votre compte MyCompanyDesk. Changez-le depuis <strong>Profil &gt; Mot de passe</strong>.</p><h3 id="exigences-du-mot-de-passe" tabindex="-1">Exigences du mot de passe <a class="header-anchor" href="#exigences-du-mot-de-passe" aria-label="Permalink to &quot;Exigences du mot de passe&quot;">​</a></h3><ul><li>Au moins 8 caracteres</li><li>Un melange de lettres, chiffres et symboles est recommande</li></ul><h2 id="authentification-a-deux-facteurs" tabindex="-1">Authentification a deux facteurs <a class="header-anchor" href="#authentification-a-deux-facteurs" aria-label="Permalink to &quot;Authentification a deux facteurs&quot;">​</a></h2><p>Ajoutez une couche de securite supplementaire a votre compte :</p><ol><li>Allez dans <strong>Profil &gt; Securite</strong></li><li>Cliquez sur <strong>Activer l&#39;authentification a deux facteurs</strong></li><li>Scannez le QR code avec votre application d&#39;authentification (Google Authenticator, Authy, etc.)</li><li>Entrez le code de verification pour confirmer</li><li>Enregistrez vos <strong>codes de recuperation</strong> dans un endroit securise</li></ol><p>Avec l&#39;authentification a deux facteurs activee, vous aurez besoin de votre mot de passe et d&#39;un code de votre application d&#39;authentification pour vous connecter.</p><h3 id="desactiver-l-authentification-a-deux-facteurs" tabindex="-1">Desactiver l&#39;authentification a deux facteurs <a class="header-anchor" href="#desactiver-l-authentification-a-deux-facteurs" aria-label="Permalink to &quot;Desactiver l&#39;authentification a deux facteurs&quot;">​</a></h3><ol><li>Allez dans <strong>Profil &gt; Securite</strong></li><li>Cliquez sur <strong>Desactiver l&#39;authentification a deux facteurs</strong></li><li>Entrez votre mot de passe pour confirmer</li></ol><h2 id="gestion-des-sessions" tabindex="-1">Gestion des sessions <a class="header-anchor" href="#gestion-des-sessions" aria-label="Permalink to &quot;Gestion des sessions&quot;">​</a></h2><p>Consultez et gerez vos sessions actives :</p><ul><li>Voyez tous les appareils et navigateurs ou vous etes connecte</li><li>Consultez l&#39;heure de la derniere activite pour chaque session</li><li><strong>Revoquez</strong> les sessions que vous ne reconnaissez pas</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Si vous voyez une session que vous ne reconnaissez pas, revoquez-la immediatement et changez votre mot de passe.</p></div><h2 id="connexion-sociale" tabindex="-1">Connexion sociale <a class="header-anchor" href="#connexion-sociale" aria-label="Permalink to &quot;Connexion sociale&quot;">​</a></h2><p>Si vous utilisez Google ou Microsoft pour vous connecter :</p><ul><li>Votre authentification est geree par le fournisseur</li><li>MyCompanyDesk ne voit ni ne stocke jamais votre mot de passe Google/Microsoft</li><li>Vous pouvez deconnecter la connexion sociale depuis <strong>Profil &gt; Applications connectees</strong></li></ul><h2 id="protection-des-donnees" tabindex="-1">Protection des donnees <a class="header-anchor" href="#protection-des-donnees" aria-label="Permalink to &quot;Protection des donnees&quot;">​</a></h2><p>MyCompanyDesk prend la securite des donnees au serieux :</p><ul><li>Toutes les donnees sont transmises via HTTPS</li><li>Les mots de passe sont haches avec bcrypt</li><li>Les connexions a la base de donnees sont chiffrees</li><li>Des sauvegardes regulieres assurent la securite des donnees</li><li>Traitement des donnees conforme au RGPD</li></ul><h2 id="suppression-du-compte" tabindex="-1">Suppression du compte <a class="header-anchor" href="#suppression-du-compte" aria-label="Permalink to &quot;Suppression du compte&quot;">​</a></h2><p>Si vous devez supprimer votre compte :</p><ol><li>Allez dans <strong>Profil &gt; Donnees</strong></li><li>Cliquez sur <strong>Supprimer le compte</strong></li><li>Entrez votre mot de passe pour confirmer</li><li>Toutes vos donnees sont definitivement supprimees</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>La suppression du compte est irreversible. Exportez vos donnees au prealable si vous avez besoin d&#39;une sauvegarde.</p></div>',26)])])}const m=s(a,[["render",n]]);export{h as __pageData,m as default};
